var e=[{id:`L2_1`,type:`dialog`,speaker:`SEO_YOON_ALT_CA_NULL`,text:{KOREA:`저 사람은…… 황태자……? 살아 있었어?`,JPN:`あの人は……皇太子……？　生きていたの？`,ENG:`That's... the Crown Prince...! He's alive...?`,TWN:`那個人是……皇太子……？他還活著？`},stage:{bg:`MS_903`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`게다가 병사들까지 끌고 왔어.`,JPN:`それに、兵士まで引き連れてきてる。`,ENG:`He even brought soldiers.`,TWN:`還是帶著士兵過來的。`},stage:{bg:`MS_903`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`잠깐, 그렇다면 부사장님이랑 다른 사람들은…….`,JPN:`待って、じゃあ副社長や他のみんなは……`,ENG:`Wait, then the Vice President and the others...`,TWN:`等等，那副總和其他人不就……`},stage:{bg:`MS_903`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_CA_NULL`,text:{KOREA:`미나 양, 동요하지 마세요.`,JPN:`ミナさん、落ち着いてください。`,ENG:`Keep calm, Mina.`,TWN:`米娜，別動搖。`},stage:{bg:`MS_903`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:`PRINCE_KNIGHT_NULL_NULL`,text:{KOREA:`엄격하게 통솔되지 않는 군대를 각개격파하는 건 그리 어려운 일도 아니지.`,JPN:`統率の甘い軍隊を分散させ潰していくのはそう難しいことではない。`,ENG:`It's not so hard to break through an army that lacks a proper leader.`,TWN:`將沒有嚴格統率的軍隊逐個擊破，也不是什麼難事。`},stage:{bg:`MS_903`,slots:{L:null,C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:`PRINCE_KNIGHT_NULL_NULL`,text:{KOREA:`알렌 경. 마르티네즈 공. 저 자들을 포위해라.`,JPN:`バーミンガム卿。マルチネス卿。あの者たちを包囲しろ。`,ENG:`Sir Allen. Marquise Martinez. Surround them.`,TWN:`艾倫卿，馬汀尼茲侯爵，包圍那些人。`},stage:{bg:`MS_903`,slots:{L:null,C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:`ALLEN_ORDER_NULL_NULL`,text:{KOREA:`명을 받들겠습니다, 전하.`,JPN:`かしこまりました、殿下。`,ENG:`As you wish, Your Highness.`,TWN:`遵命，殿下。`},stage:{bg:`MS_903`,slots:{L:{char_id:`ALLEN_ORDER_NULL_NULL`,face:`UNIT_DESPAIR`},C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`CHARLOTTE_ORDER_NULL_NULL`,text:{KOREA:`전군! 전개!`,JPN:`全軍！　展開！`,ENG:`All troops! Forward!`,TWN:`全軍！展開！`},stage:{bg:`MS_903`,slots:{L:{char_id:`ALLEN_ORDER_NULL_NULL`,face:`UNIT_DESPAIR`},C:null,R:{char_id:`CHARLOTTE_ORDER_NULL_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L13_1`,type:`dialog`,speaker:`PRINCE_KNIGHT_NULL_NULL`,text:{KOREA:`그나저나…… 그 여자가 결국 일을 저지르고 말았군.`,JPN:`それにしても……あの女が結局はやらかしたか。`,ENG:`On another note... It seems that woman finally did it.`,TWN:`話說回來……那個女人最終還是闖禍了。`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:{char_id:`PRINCE_KNIGHT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`RAY_SCHOOL_NPC_B`,text:{KOREA:`전하…… 저는…….`,JPN:`殿下……僕は……`,ENG:`Your Highness, I...`,TWN:`殿下……我……`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:{char_id:`RAY_SCHOOL_NPC_B`,face:`UNIT_DESPAIR`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`PRINCE_KNIGHT_NULL_NULL`,text:{KOREA:`끝까지 적 앞에서 약한 모습을 보일 셈인가, 평민.`,JPN:`いつになったら敵の前で冷静になりきれるんだ、平民。`,ENG:`Do you still intend to show your weakness to the enemy, peasant?`,TWN:`你想在敵人面前一直表現出軟弱的樣子嗎，平民？`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:{char_id:`PRINCE_KNIGHT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`PRINCE_KNIGHT_NULL_NULL`,text:{KOREA:`예상은 했다만, 아직도 마음을 다잡지 못하고 있었군.`,JPN:`予想はしていたが、まだ心が揺らいでいるようだな。`,ENG:`I assumed so, but it's clear that you haven't made up your mind.`,TWN:`雖然早預料到了，但是你現在還沒下定決心啊。`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:{char_id:`PRINCE_KNIGHT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`RAY_SCHOOL_NPC_B`,text:{KOREA:`…….`,JPN:`……`,ENG:`...`,TWN:`……`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:{char_id:`RAY_SCHOOL_NPC_B`,face:`UNIT_DESPAIR`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`PRINCE_KNIGHT_NULL_NULL`,text:{KOREA:`네 공연은 끝이다.`,JPN:`貴様の芝居はここまでだ。`,ENG:`Your phony show is over.`,TWN:`你的演出結束了。`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:{char_id:`PRINCE_KNIGHT_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`PRINCE_KNIGHT_NULL_NULL`,text:{KOREA:`하다못해 네가 지키고 있어야 할 옥좌로 돌아가라. 그 여자와 함께.`,JPN:`せめて貴様が守るべき玉座に戻れ。その女と共に。`,ENG:`Go back to the throne that you should be sitting on. Take the girl with you.`,TWN:`你還是回到你的那個寶座上去吧，和那個女人一起。`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:{char_id:`PRINCE_KNIGHT_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`RAY_SCHOOL_NPC_B`,text:{KOREA:`……죄송합니다, 전하. 뒤를 부탁드립니다.`,JPN:`……申し訳ありません、殿下。後はお願いします。`,ENG:`...Forgive me, Your Highness. I leave the rest to you.`,TWN:`對不起，殿下。後面就拜託您了。`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:{char_id:`RAY_SCHOOL_NPC_B`,face:`UNIT_DESPAIR`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`선배, 방금 전보다 상황이 더 안 좋아진 것 같아.`,JPN:`先輩、さっきよりもっと状況が悪くなったんじゃないかな。`,ENG:`I think things just got worse, Shiyoon.`,TWN:`局勢好像變得比剛才更差了，前輩……`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`JOOSHIYOON_FENRIR_CA_NULL`,face:`UNIT_IDLE`}}}}];export{e as default};